if fh_l then
    local row = fh_l:readLine()
    print("first row:", row)
    fh_l:close()
end

-- ---- Stub: FileHandle:write ----------------------------------------------
--@api-stub: FileHandle:write
-- Serialise a settings table to the save directory by writing each
-- key-value pair as a line, then flushing to disk.
local fh_w = lurek.filesystem.openFile("save/settings.txt", "w")
if fh_w then
    local bytes = fh_w:write("volume=80\n")
    print("bytes written:", bytes)
    fh_w:flush()
    fh_w:close()
end

-- ---- Stub: FileHandle:seek -----------------------------------------------
--@api-stub: FileHandle:seek
-- Jump to a specific byte offset to read the header of a binary file
-- format without loading the entire file into memory.
local fh_s = lurek.filesystem.openFile("save/progress.dat", "r")
if fh_s then
    fh_s:seek(0)  -- rewind to start
    print("seeked to:", fh_s:tell())
    fh_s:close()
end

-- ---- Stub: FileHandle:tell -----------------------------------------------
--@api-stub: FileHandle:tell
-- Read the cursor position after seeking to verify the correct offset
-- before issuing a fixed-size read for a binary record.
local fh_t = lurek.filesystem.openFile("save/progress.dat", "r")
if fh_t then
    print("initial cursor:", fh_t:tell())  -- 0
    fh_t:close()
end

-- ---- Stub: FileHandle:getSize --------------------------------------------
--@api-stub: FileHandle:getSize
-- Check the file size before allocating a read buffer so oversized
-- files do not consume unexpected memory.
local fh_sz = lurek.filesystem.openFile("save/progress.dat", "r")
if fh_sz then
    print("file size:", fh_sz:getSize(), "bytes")
