-- ---- Stub: FileHandle:getMode --------------------------------------------
--@api-stub: FileHandle:getMode
-- Verify the access mode before calling write to surface an early
-- programmer error when the wrong mode string was passed to openFile.
local fh_m = lurek.filesystem.openFile("save/progress.dat", "r")
if fh_m then
    print("mode:", fh_m:getMode())  -- "r"
    fh_m:close()
end

-- ---- Stub: FileHandle:flush ----------------------------------------------
--@api-stub: FileHandle:flush
-- Flush writes to disk after each autosave checkpoint so data is safe
-- even if the game crashes before the file is explicitly closed.
local fh_f = lurek.filesystem.openFile("save/autosave.dat", "w")
if fh_f then
    fh_f:write("checkpoint_1\n")
    fh_f:flush()  -- ensure checkpoint is on disk
    fh_f:close()
end

-- ---- Stub: FileHandle:close ----------------------------------------------
--@api-stub: FileHandle:close
-- Always close file handles after reading or writing to release the
-- OS file descriptor and ensure all buffered writes are committed.
local fh_c = lurek.filesystem.openFile("data/level_01.txt", "r")
if fh_c then
    local content = fh_c:read(256)
    fh_c:close()  -- release handle immediately after reading
    print("read", #content, "bytes")
end

-- ---- Stub: FileHandle:isEOF ----------------------------------------------
--@api-stub: FileHandle:isEOF
-- Loop reading lines from a text file until isEOF returns true so
-- the loop exits cleanly without needing the line count in advance.
local fh_eof = lurek.filesystem.openFile("data/dialogue.txt", "r")
if fh_eof then
    while not fh_eof:isEOF() do
        local line = fh_eof:readLine()
        if line then print(line) end
    end
    fh_eof:close()
end

